+type TranscriptSegment = { startSeconds: number; text: string };
+
+const MAX_SLIDE_TRANSCRIPT_CHARS_BY_PRESET = {
+  short: 2500,
+  medium: 5000,
+  long: 9000,
+  xl: 15000,
+  xxl: 24000,
+} as const;
