+  ffmpegPath: string;
+  inputPath: string;
+  threshold: number;
+  timeoutMs: number;
+  segments?: Array<{ start: number; duration: number }>;
+  workers?: number;
+  onSegmentProgress?: ((completed: number, total: number) => void) | null;
+  runWithConcurrency: <T>(
+    tasks: Array<() => Promise<T>>,
+    workers: number,
+    onProgress?: ((completed: number, total: number) => void) | null,
+  ) => Promise<T[]>;
