+    const timestamps: number[] = [];
+    await runProcess({
+      command: ffmpegPath,
+      args: [
+        "-hide_banner",
+        ...(segment.duration > 0
+          ? ["-ss", String(segment.start), "-t", String(segment.duration)]
+          : []),
+        "-i",
+        inputPath,
+        "-vf",
