+export function mergeTimestamps(
+  sceneTimestamps: number[],
+  intervalTimestamps: number[],
+  minDurationSeconds: number,
+): number[] {
+  const merged = [...sceneTimestamps, ...intervalTimestamps].filter((value) =>
