+export function selectTimestampTargets({
+  targets,
+  sceneTimestamps,
+  minDurationSeconds,
+  intervalSeconds,
+}: {
+  targets: number[];
+  sceneTimestamps: number[];
+  minDurationSeconds: number;
+  intervalSeconds: number;
