+  if (!Number.isFinite(intervalSeconds) || intervalSeconds <= 0) return null;
+  const timestamps: number[] = [];
+  for (let t = 0; t < durationSeconds; t += intervalSeconds) timestamps.push(t);
+  return { timestamps, intervalSeconds };
